postToolUse.powershell:
$inputText = [Console]::In.ReadToEnd()
New-Item -ItemType Directory -Force -Path .vstack/logs | Out-Null
Add-Content -Path .vstack/logs/hook-post-edit.jsonl -Value $inputText
$mode = if ($env:VSTACK_HOOKS_MODE) { $env:VSTACK_HOOKS_MODE } else { 'audit' }
if ($mode -ne 'enforce') {
  exit 0
}
try {
  $payload = $inputText | ConvertFrom-Json -ErrorAction Stop
} catch {
  exit 0
}
if ($payload.toolName -match '^(edit|create|write|replace)$') {
  if ((Test-Path Makefile) -and (Get-Command make -ErrorAction SilentlyContinue)) {
    make format *> $null
    if ($LASTEXITCODE -ne 0) {
      Add-Content -Path .vstack/logs/hook-quality-alerts.log -Value 'format-run-failed'
    }
  } else {
    Add-Content -Path .vstack/logs/hook-quality-alerts.log -Value 'format-skipped-missing-make-or-makefile'
  }
}
